import{_ as t,a,b as o,c as n,d as r}from"./chunks/编辑配置.T0puvWjh.js";import{_ as d,o as l,c as i,a2 as h}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Add a Telegram Channel","description":"","frontmatter":{},"headers":[],"relativePath":"en/upload/telegram.md","filePath":"en/upload/telegram.md","lastUpdated":1781962217000}'),s={name:"en/upload/telegram.md"};function c(p,e,m,u,b,g){return l(),i("div",null,[...e[0]||(e[0]=[h('<h1 id="add-a-telegram-channel" tabindex="-1">Add a Telegram Channel <a class="header-anchor" href="#add-a-telegram-channel" aria-label="Permalink to &quot;Add a Telegram Channel&quot;">​</a></h1><h2 id="what-you-need-before-you-start" tabindex="-1">What You Need Before You Start <a class="header-anchor" href="#what-you-need-before-you-start" aria-label="Permalink to &quot;What You Need Before You Start&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>Telegram account</td><td>Used to create the bot and the storage channel.</td></tr><tr><td><code>@BotFather</code></td><td>Used to create a Telegram bot.</td></tr><tr><td>A Telegram channel</td><td>The final storage destination for files.</td></tr><tr><td><code>@userinfobot</code></td><td>Used to look up the channel <code>Chat ID</code>.</td></tr></tbody></table><h2 id="where-to-add-it" tabindex="-1">Where to Add It <a class="header-anchor" href="#where-to-add-it" aria-label="Permalink to &quot;Where to Add It&quot;">​</a></h2><ol><li>Open System Settings.</li><li>Go to Upload Settings.</li><li>Click Add Channel in the upper-right corner.</li><li>Select <code>Telegram</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>What It Does</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>A friendly name for this channel, such as &quot;Telegram Primary&quot;.</td><td>Required</td></tr><tr><td>Active</td><td>Enables or disables this channel.</td><td>Recommended</td></tr><tr><td>Bot Token</td><td>The token of your Telegram bot.</td><td>Required</td></tr><tr><td>Session ID (Chat ID)</td><td>The ID of the Telegram channel.</td><td>Required</td></tr><tr><td>Relay Proxy URL (optional)</td><td>Use this only if Telegram access is unstable. Enter the full proxy URL, including <code>https://</code>.</td><td>Optional</td></tr><tr><td>Remark</td><td>Notes for future maintenance.</td><td>Optional</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="_1-create-a-telegram-bot" tabindex="-1">1. Create a Telegram Bot <a class="header-anchor" href="#_1-create-a-telegram-bot" aria-label="Permalink to &quot;1. Create a Telegram Bot&quot;">​</a></h3><ol><li>Open Telegram and search for <code>@BotFather</code>.</li><li>Open the chat and click <code>Start</code>.</li><li>Send <code>/newbot</code>.</li><li>Follow the prompts to enter a bot display name.</li><li>Follow the prompts to enter a bot username. The username usually needs to end with <code>bot</code>.</li><li>After the bot is created, <code>@BotFather</code> will return a bot token.</li></ol><p>This token is the <code>Bot Token</code> you need to enter in ImgBed.</p><p><img src="'+t+'" alt="Save the bot token" loading="lazy"></p><h3 id="_2-create-a-channel" tabindex="-1">2. Create a Channel <a class="header-anchor" href="#_2-create-a-channel" aria-label="Permalink to &quot;2. Create a Channel&quot;">​</a></h3><ol><li>In Telegram, click New Channel.</li><li>Enter a channel name.</li><li>Finish creating the channel.</li></ol><p>Both public and private channels can be used.</p><p><img src="'+a+'" alt="Create a channel" loading="lazy"></p><h3 id="_3-add-the-bot-to-the-channel" tabindex="-1">3. Add the Bot to the Channel <a class="header-anchor" href="#_3-add-the-bot-to-the-channel" aria-label="Permalink to &quot;3. Add the Bot to the Channel&quot;">​</a></h3><ol><li>Open the channel you just created.</li><li>Open the channel settings.</li><li>Add a member or administrator.</li><li>Search for the bot username you created.</li><li>Add the bot to the channel.</li></ol><p>For the most reliable uploads, grant the bot administrator permissions.</p><p><img src="'+o+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-get-the-channel-id-with-user-info-get-id-idbot" tabindex="-1">4. Get the Channel ID with User Info - Get ID - IDbot <a class="header-anchor" href="#_4-get-the-channel-id-with-user-info-get-id-idbot" aria-label="Permalink to &quot;4. Get the Channel ID with User Info - Get ID - IDbot&quot;">​</a></h3><ol><li>Search for <code>@userinfobot</code> in Telegram. Its display name is usually <code>User Info - Get ID - IDbot</code>.</li><li>Open the chat and click <code>Start</code>.</li><li>Choose <code>Channel</code> from the options provided by the bot.</li><li>In the message picker, select the target channel and send it to <code>@userinfobot</code>.</li><li>When <code>@userinfobot</code> returns the result, copy the number shown as <code>Id: -100...</code>.</li></ol><p>The number starting with <code>-100</code> is the <code>Session ID (Chat ID)</code> required by ImgBed.</p><p><img src="'+n+'" alt="Get the channel ID" loading="lazy"></p><h3 id="_5-fill-in-the-telegram-channel-in-imgbed" tabindex="-1">5. Fill in the Telegram Channel in ImgBed <a class="header-anchor" href="#_5-fill-in-the-telegram-channel-in-imgbed" aria-label="Permalink to &quot;5. Fill in the Telegram Channel in ImgBed&quot;">​</a></h3><p>Return to the channel configuration dialog and fill in the fields as follows:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>A custom channel name, for example <code>TelegramPrimary</code>.</td></tr><tr><td>Active</td><td>Recommended.</td></tr><tr><td>Bot Token</td><td>The bot token from <code>@BotFather</code>.</td></tr><tr><td>Session ID (Chat ID)</td><td>The <code>-100...</code> number returned by <code>@userinfobot</code>.</td></tr><tr><td>Relay Proxy URL (optional)</td><td>Only if needed, for example <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Remark</td><td>Optional notes.</td></tr></tbody></table><p>Click Save when you are done.</p><p><img src="'+r+`" alt="Edit the configuration" loading="lazy"></p><h2 id="how-to-verify-it" tabindex="-1">How to Verify It <a class="header-anchor" href="#how-to-verify-it" aria-label="Permalink to &quot;How to Verify It&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>How to Verify</th></tr></thead><tbody><tr><td>Channel card appears</td><td>After saving, the Upload Settings page should show a Telegram channel card.</td></tr><tr><td>Channel can be enabled</td><td>The Active switch should stay on.</td></tr><tr><td>Configuration is saved</td><td>The detail view should show that the Bot Token and Chat ID were saved.</td></tr><tr><td>Upload works</td><td>Upload a test image and confirm that it appears in the target Telegram channel.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Create a bot with @BotFather</span></span>
<span class="line"><span>-&gt; Save the Bot Token</span></span>
<span class="line"><span>-&gt; Create a Telegram channel</span></span>
<span class="line"><span>-&gt; Add the bot to the channel and grant administrator permissions</span></span>
<span class="line"><span>-&gt; Search for @userinfobot and choose Channel</span></span>
<span class="line"><span>-&gt; Forward any message from the channel to @userinfobot</span></span>
<span class="line"><span>-&gt; Copy the returned Id: -100...</span></span>
<span class="line"><span>-&gt; Enter the Bot Token and Chat ID in ImgBed</span></span>
<span class="line"><span>-&gt; Save and upload a test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const T=d(s,[["render",c]]);export{k as __pageData,T as default};
